INSERT INTO `adms_cham_hist` (`id`, `status`, `dt_status`, `cham_id`, `usr_id`, `obs`, `created`, `modified`) VALUES
(5578, 'Finalizado', '2025-09-05 11:58:40', 2340, 445, 'Foi realizado o treinamento do sistema, Marcia não estava presente devido a urgência,  e foi feito com Milena. Durante o treinamento apresentei as partes principais que serão utilizadas pela cliente, cadastro de novos funcionários e acompanhamento do ponto para repassar as observações por email, os usuários de Renata, Marcia e Milena não consegue fazer alterações no ponto dos funcionários,  somente acompanhamento, isso solicitado por elas mesmo. Foi configurado o banco de horas para atender a realidade do cliente, onde feriados não serão contabilizados para o banco, caso trabalhados, e parametrizei todos os horários cadastrados, desativando os que não estavam sendo utilizados, a maioria estava com configurações incorretas, ajustei todos para ficar com a jornada inserida corretamente e incluir os feriados faltantes referentes ao ano de 2025. Orientei a retificar o ponto semanalmente para mandarem o email com todas as informações autorizadas a lançar, e vão estar enviando sempre após o dia 15, que seria após o fechamento da folha, quaisquer ocorrência identificada na conferência que não esteja no e-mail,  será repassado para Marcia e solicitado autorização para corrigir ou não,  caso autorizado, será lançado no ponto do funcionário e no momento de enviar o fechamento da folha, será retificado os ajustes que foram feitos sob autorização da mesma.', '2025-09-05 11:58:40', NULL),
(5579, 'Finalizado', '2025-09-05 13:20:00', 2416, 445, 'Sistema anterior utilizado pela cliente era por outra revenda, informei que a implementação feita pela Rep brasil foi do zero, orientei a procurar pela revenda anterior para buscar as informações do sistema antigo.', '2025-09-05 13:20:00', NULL),
