(5756, 'Finalizado', '2025-09-11 13:12:25', 2473, 445, 'Repassei a informação de que o relógio henry prisma superfacil r02 funciona com cartão de proximidade, mas era necessário identificar o cartão correto para utilização.', '2025-09-11 13:12:25', NULL),
(5757, 'Aguardando Cliente', '2025-09-11 13:41:23', 2475, 445, 'O relógio indica estar desconectado do cabo de internet, o cliente está esperando o TI chegar no local para verificar se a informação procede. Aguardando confirmação.', '2025-09-11 13:41:23', NULL),
(5758, 'Finalizado', '2025-09-11 13:52:11', 2486, 445, 'Orientei a desabilitar a opção de usar licença offline e enviei as configurações online para o aplicativo, problema resolvido para registro e cadastro das faciais.', '2025-09-11 13:52:11', NULL),
