(5815, 'Finalizado', '2025-09-12 12:11:18', 2498, 445, 'Foi realizado a configuração do relógio de ponto antes da visita, com todos os colaboradores/CNPJ cadastrados, na visita a instalação foi feita com êxito e orientei a Priscila a como realizar o cadastro das digitais e de como trocar bobina do relógio quando necessário, devido a solicitação da mesma, apliquei ao cadastro da mesma a ser administradora, para que colaboradores não tenham acesso ao menu do rep. A configuração de rede foi aplicada e já comunica direto com o sistema de ponto, diante de teste feito puxando a batida registrada pela cliente.', '2025-09-12 12:11:18', NULL),
(5816, 'Em Atendimento', '2025-09-12 12:12:42', 2501, 445, 'Inicializado as 12:12:42 hs. do dia 12-09-2025', '2025-09-12 12:12:42', NULL),
(5817, 'Em Atendimento', '2025-09-12 13:51:36', 2497, 446, 'Inicializado as 13:51:36 hs. do dia 12-09-2025', '2025-09-12 13:51:36', NULL),
