(5819, 'Aguardando Comercial', '2025-09-12 13:52:19', 2497, 446, 'Necessário a visita para verificar a situação do computador.', '2025-09-12 13:52:19', NULL),
(5820, 'Finalizado', '2025-09-12 14:01:40', 2469, 446, 'Foi feita a instalação dos drivers do ecuro junto com o aplicativo no consultório 7 na maquina de patrimônio 005803 e no consultório 14 na maquina de patrimônio 005782. No 7 vai ser necessário a troca da placa pois a que se encontra na maquina esta ultrapassada juntamente com o adaptador wifi que não estão suprindo a necessidade do consultório.', '2025-09-12 14:01:40', NULL),
(5821, 'Em Atendimento', '2025-09-12 15:43:23', 2505, 445, 'Inicializado as 15:43:23 hs. do dia 12-09-2025', '2025-09-12 15:43:23', NULL),
(5822, 'Finalizado', '2025-09-12 15:44:36', 2501, 445, 'Conforme solicitado, criei o novo departamento e configurei o novo aplicativo, orientei que o cliente instalasse o mesmo para começar o registro da jornada dos novos funcionários.', '2025-09-12 15:44:36', NULL),
(5823, 'Finalizado', '2025-09-12 15:55:21', 2505, 445, 'Acessei o computador local, e instalei o comunicador novamente para conectar ao ponto da loja do alphaville, comunicação reestabelecida\r\n', '2025-09-12 15:55:21', NULL),
(5824, 'Em Atendimento', '2025-09-12 16:19:36', 2506, 445, 'Inicializado as 16:19:36 hs. do dia 12-09-2025', '2025-09-12 16:19:36', NULL),
