INSERT INTO `adms_cham_hist` (`id`, `status`, `dt_status`, `cham_id`, `usr_id`, `obs`, `created`, `modified`) VALUES
(5843, 'Em Atendimento', '2025-09-15 12:23:01', 2342, 445, 'Inicializado as 12:23:01 hs. do dia 15-09-2025', '2025-09-15 12:23:01', NULL),
(5844, 'Finalizado', '2025-09-15 12:25:43', 2342, 445, 'Relógio foi configurado na rede local. Não foi possível efetuar a instalação pois ainda não estava definido em qual localidade o relógio ficaria e não havia cabo de internet para a conexão. Para a configuração utilizei meu cabo de teste e configurei o mesmo para comunicar com o sistema, orientei a cliente a somente cadastrar as biometrias dos funcionários. Instalação ficou por parte do cliente quando o local for decidido. Para funcionamento o notebook de Jessica deve estar sempre conectado ao wifi OceamBreeze, repassei isso para a mesma.', '2025-09-15 12:25:43', NULL),
(5845, 'Finalizado', '2025-09-15 12:27:29', 2513, 445, 'Orientei a cliente que a cada registro feito no app central, ele declara na página inicial todos os registros feitos pelo funcionário,  sendo offline ou online. Caso o mesmo não apareça nesta informação na tela inicial, é porque o registro não foi realizado devido a alguma outra questão que não foi mencionada neste caso.', '2025-09-15 12:27:29', NULL),
(5846, 'Em Atendimento', '2025-09-15 13:45:54', 2521, 445, 'Inicializado as 13:45:54 hs. do dia 15-09-2025', '2025-09-15 13:45:54', NULL),
(5847, 'Reagendado', '2025-09-15 13:47:37', 2393, 445, 'Reagendado as 13:47:37 hs. do dia 15-09-2025', '2025-09-15 13:47:37', NULL),
(5848, 'Em Atendimento', '2025-09-15 13:47:39', 2393, 445, 'Inicializado as 13:47:39 hs. do dia 15-09-2025', '2025-09-15 13:47:39', NULL),
(5849, 'Finalizado', '2025-09-15 13:48:01', 2393, 445, 'Devido a falta de retorno sobre as pendências do fechamento, este chamado segue sendo finalizado.', '2025-09-15 13:48:01', NULL),
(5850, 'Em Atendimento', '2025-09-15 13:49:46', 2522, 445, 'Inicializado as 13:49:46 hs. do dia 15-09-2025', '2025-09-15 13:49:46', NULL),
(5851, 'Finalizado', '2025-09-15 14:03:46', 2522, 445, 'Informei que devido a haver 2 CNPJs diferentes no sistema, mesmo com a restrição para cada usuário visualizar a sua, há informações que continuarão aparecendo para ambos, como horários cadastrados, números de matrículas que podem ser iguais não poderão ser cadastrados e etc. Informei que esta situação foi tratada com Jéssica, e já está sendo verificado a possibilidade de alocar este novo CNPJ em um novo banco web, a parte do barra residence.', '2025-09-15 14:03:46', NULL),
(5852, 'Finalizado', '2025-09-15 14:41:42', 2521, 445, 'Orientação de como readmitir um colaborador demitido no sistema.', '2025-09-15 14:41:42', NULL),
(5853, 'Em Atendimento', '2025-09-15 15:33:04', 2512, 446, 'Inicializado as 15:33:04 hs. do dia 15-09-2025', '2025-09-15 15:33:04', NULL),
(5854, 'Aguardando Comercial', '2025-09-15 15:34:19', 2512, 446, 'Necessário visita para verificar qual a peça que esta faltando.', '2025-09-15 15:34:19', NULL),
(5855, 'Em Atendimento', '2025-09-15 15:34:50', 2507, 446, 'Inicializado as 15:34:50 hs. do dia 15-09-2025', '2025-09-15 15:34:50', NULL),
(5856, 'Em Atendimento', '2025-09-15 15:49:27', 2515, 445, 'Inicializado as 15:49:27 hs. do dia 15-09-2025', '2025-09-15 15:49:27', NULL),
(5857, 'Finalizado', '2025-09-15 15:52:02', 2515, 445, 'Apresentação realizada, cliente pretende usar Central do funcionário para colaboradores externos, banco de horas, tirei duvidas sobre localização ficticia no aplicativo central e pretendem usar reconhecimento facial. Ficou interessado em utilizar o sistema em período de teste, para validar as questões de geolocalização', '2025-09-15 15:52:02', NULL),
(5858, 'Finalizado', '2025-09-15 15:54:06', 2514, 445, 'Informei que esta notificação é configurada no próprio aplicativo, e pode ser alterada caso não queira ser notificado, mandei print declarando que o app notifica no exato momento que o funcionário deve registrar conforme sua jornada de trabalho definida, mas está sujeito a receber  a notificação em um horário diferente caso tenha problema de conectividade ou outras situações externas que podem influenciar na notificação recebida.', '2025-09-15 15:54:06', NULL),
(5859, 'Em Atendimento', '2025-09-15 16:06:14', 2523, 445, 'Inicializado as 16:06:14 hs. do dia 15-09-2025', '2025-09-15 16:06:14', NULL),
(5860, 'Finalizado', '2025-09-15 16:25:07', 2523, 445, 'Orientei a como desabilitar a opção de inclusão de ponto através do app central do funcionário, e criei um novo perfil para \"funcionários internos\", onde os mesmos não conseguem solicitar ajustes no próprio ponto, e colaboradores externos ficam no perfil de \"funcionários externos\", onde conseguem solicitar ajustes quando necessário.', '2025-09-15 16:25:07', NULL),
(5861, 'Aguardando Cliente', '2025-09-15 16:57:24', 2496, 445, 'Entrei em contato novamente e a cliente deu retorno. Fiz um acesso remoto e orientei a como funcionaria a parametrização do banco de horas no sistema offline, a mesma informou que vai estar passando as informações para a diretoria e pedir o aval para após isso configurarmos o banco de horas no sistema.', '2025-09-15 16:57:24', NULL),
(5862, 'Aguardando Cliente', '2025-09-15 16:58:29', 2436, 445, 'Vim novamente  a entrar em contato com a cliente, a mesma informou que o pessoal do TI irá liberar o acesso ao servidor para fazermos o registro do sistema, porém só vão poder fazer a liberação amanhã, 16/09 a partir de 09:00', '2025-09-15 16:58:29', NULL),
(5863, 'Pausado', '2025-09-15 17:08:51', 2454, 445, 'Foi validado que o relógio apresenta defeito na fonte de alimentação e na bateria interna. Necessário troca da bateria CR2032 e da fonte de alimentação para resolução do problema. Laudo técnico foi encaminhado para o setor comercial.', '2025-09-15 17:08:51', NULL),
(5864, 'Em Atendimento', '2025-09-16 08:36:13', 2524, 445, 'Inicializado as 08:36:13 hs. do dia 16-09-2025', '2025-09-16 08:36:13', NULL),
(5865, 'Finalizado', '2025-09-16 08:42:29', 2524, 445, 'Removi as configurações de reconhecimento do aplicativo, para que não precise enquadrar o rosto em determinado ponto para conseguir registrar.', '2025-09-16 08:42:29', NULL),
(5866, 'Em Atendimento', '2025-09-16 08:42:41', 2526, 445, 'Inicializado as 08:42:41 hs. do dia 16-09-2025', '2025-09-16 08:42:41', NULL),
(5867, 'Finalizado', '2025-09-16 08:51:44', 2526, 445, 'Orientação de como fazer os lançamentos de ajustes parciais corretamente, para não contabilizar horas extras indevidas.', '2025-09-16 08:51:44', NULL),
(5868, 'Em Atendimento', '2025-09-16 08:56:23', 2528, 445, 'Inicializado as 08:56:23 hs. do dia 16-09-2025', '2025-09-16 08:56:23', NULL),
(5869, 'Finalizado', '2025-09-16 09:17:37', 2528, 445, 'Ensinei como funciona os perímetros configurados, e orientei a como fazer a inclusão de perímetros individuais.', '2025-09-16 09:17:37', NULL),
(5870, 'Em Atendimento', '2025-09-16 09:17:46', 2529, 445, 'Inicializado as 09:17:46 hs. do dia 16-09-2025', '2025-09-16 09:17:46', NULL),
(5871, 'Em Atendimento', '2025-09-16 09:18:19', 2530, 445, 'Inicializado as 09:18:19 hs. do dia 16-09-2025', '2025-09-16 09:18:19', NULL),
(5872, 'Finalizado', '2025-09-16 09:22:33', 2530, 445, 'A dúvida se referia a saber se deslogar a conta google do aparelho, influenciaria no uso do aplicativo, repassei a informação de que mesmo removendo a conta o aplicativo para registro de ponto irá funcionar normal.', '2025-09-16 09:22:33', NULL),
(5873, 'Finalizado', '2025-09-16 09:30:05', 2529, 445, 'Havia um ajuste no banco de horas lançado no dia em questão, orientei a como remover ajustes lançados indevidamente.', '2025-09-16 09:30:05', NULL),
(5874, 'Reagendado', '2025-09-16 09:32:05', 2485, 446, 'Reagendado as 09:32:05 hs. do dia 16-09-2025', '2025-09-16 09:32:05', NULL),
(5875, 'Em Atendimento', '2025-09-16 09:32:07', 2485, 446, 'Inicializado as 09:32:07 hs. do dia 16-09-2025', '2025-09-16 09:32:07', NULL),
(5876, 'Finalizado', '2025-09-16 10:01:13', 2485, 446, 'Foi feita a configuração do computador para que a tela não fique desligando após 15 minutos.', '2025-09-16 10:01:13', NULL),
(5877, 'Reagendado', '2025-09-16 10:36:59', 2436, 445, 'Reagendado as 10:36:59 hs. do dia 16-09-2025', '2025-09-16 10:36:59', NULL),
(5878, 'Em Atendimento', '2025-09-16 10:37:03', 2436, 445, 'Inicializado as 10:37:03 hs. do dia 16-09-2025', '2025-09-16 10:37:03', NULL),
