(5883, 'Reagendado', '2025-09-16 11:50:31', 2497, 446, 'Reagendado as 11:50:31 hs. do dia 16-09-2025', '2025-09-16 11:50:31', NULL),
(5884, 'Em Atendimento', '2025-09-16 11:50:33', 2497, 446, 'Inicializado as 11:50:33 hs. do dia 16-09-2025', '2025-09-16 11:50:33', NULL),
(5885, 'Finalizado', '2025-09-16 11:50:40', 2532, 445, 'O funcionário estava sendo enviado como exclusão e alteração, fiz a mudança e enviei como inclusão regularizando o problema. Orientei a como incluir observações em datas especificas, e as mesmas aparecerem no relatório impresso.', '2025-09-16 11:50:40', NULL),
