(5887, 'Reagendado', '2025-09-16 11:51:16', 2525, 445, 'Reagendado as 11:51:16 hs. do dia 16-09-2025', '2025-09-16 11:51:16', NULL),
(5888, 'Finalizado', '2025-09-16 11:52:23', 2527, 445, 'Solicitação de fechamento duplicada, sendo tratado no chamado: 2525', '2025-09-16 11:52:23', NULL),
(5889, 'Em Atendimento', '2025-09-16 11:52:34', 2533, 445, 'Inicializado as 11:52:34 hs. do dia 16-09-2025', '2025-09-16 11:52:34', NULL),
(5890, 'Pausado', '2025-09-16 12:57:24', 2507, 446, 'Foi feito contato com a auxiliar a mesma não deu retorno.', '2025-09-16 12:57:24', NULL),
(5891, 'Finalizado', '2025-09-16 12:58:16', 2497, 446, 'Feita a visita e o computador estava funcionando normalmente, os doutores trocaram a CPU de local e a mesma se encontrava funcionando.', '2025-09-16 12:58:16', NULL),
(5892, 'Em Atendimento', '2025-09-16 13:02:27', 2534, 445, 'Inicializado as 13:02:27 hs. do dia 16-09-2025', '2025-09-16 13:02:27', NULL),
(5893, 'Finalizado', '2025-09-16 13:06:40', 2534, 445, 'Colaborador estava na relação dos funcionários desligados, refiz a readmissão do funcionário e já consta na lista dos ativos novamente', '2025-09-16 13:06:40', NULL),
