(6111, 'Finalizado', '2025-09-24 14:43:46', 2558, 446, 'O ssd do computador queimou completamente sendo necessário a troca do mesmo para que o computador volte a funcionar normalmente.', '2025-09-24 14:43:46', NULL),
(6112, 'Finalizado', '2025-09-24 14:43:55', 2558, 446, 'O adaptador que se encontra no consultório 2 não atente a demanda atual da internet sendo necessário a troca do mesmo para que não haja mas lentidões.', '2025-09-24 14:43:55', NULL),
(6113, 'Em Atendimento', '2025-09-24 14:48:41', 2612, 443, 'Inicializado as 14:48:41 hs. do dia 24-09-2025', '2025-09-24 14:48:41', NULL);
