(6166, 'Em Atendimento', '2025-09-29 08:34:41', 2611, 446, 'Inicializado as 08:34:41 hs. do dia 29-09-2025', '2025-09-29 08:34:41', NULL),
(6167, 'Aguardando Outros', '2025-09-29 08:36:04', 2611, 446, 'Foi passado o IP do telefone para Santana para que o mesmo pudesse realizar as configurações necessárias do telefone.', '2025-09-29 08:36:04', NULL),
(6168, 'Em Atendimento', '2025-09-29 09:56:57', 2644, 447, 'Inicializado as 09:56:57 hs. do dia 29-09-2025', '2025-09-29 09:56:57', NULL),
(6169, 'Aguardando Outros', '2025-09-29 09:59:53', 2644, 447, 'Telefones apresentando a mensagem de troncos ocupados, foi feito a tentativa de reiniciar a telefonia mas sem sucesso. Foi aberto um chamado para resolução com a Algar obtendo a seguinte mensagem: \"Obrigado por aguardar e desculpa pela demora Mauricio , foi aberto um chamado  para o circuito informado, nossa equipe nível 2 irá investigar a falha, e respectivamente, entrará em contato para lhe auxiliar na tratativa, dentro do prazo máximo de até 8 horas. O protocolo do chamado é:202528183894-2. Só aguardar o contato da nossa equipe.\"', '2025-09-29 09:59:53', NULL),
(6170, 'Em Atendimento', '2025-09-29 10:03:37', 2645, 447, 'Inicializado as 10:03:37 hs. do dia 29-09-2025', '2025-09-29 10:03:37', NULL),
(6171, 'Finalizado', '2025-09-29 10:13:01', 2645, 447, 'Foi feito a instalação do Whatsapp desktop no computador, o mesmo se encontra funcionando normalmente.', '2025-09-29 10:13:01', NULL),
(6172, 'Em Atendimento', '2025-09-29 10:43:19', 2634, 445, 'Inicializado as 10:43:19 hs. do dia 29-09-2025', '2025-09-29 10:43:19', NULL),
