(6799, 'Finalizado', '2025-10-09 15:54:48', 2816, 445, 'Cliente se referia a um período retroativo onde as configurações ainda não haviam sido devidamente feitas no horário em questão, apaguei e restaurei as batidas e as mesmas se alocaram corretamente.', '2025-10-09 15:54:48', NULL),
(6800, 'Finalizado', '2025-10-09 15:59:31', 2813, 443, 'Reinstalação foi realizada no servidor e atalhos foram criados em 2 maquinas para acesso ao sistema. sistema foi renovado a anuidade.', '2025-10-09 15:59:31', NULL),
