INSERT INTO `adms_cham_hist` (`id`, `status`, `dt_status`, `cham_id`, `usr_id`, `obs`, `created`, `modified`) VALUES
(7135, 'Aguardando Outros', '2025-10-17 09:42:11', 2803, 443, 'Entrei em contato hoje para saber o andamento do ticket aberto:\r\nyuri Machado\r\nBom dia, tudo bem?\r\n\r\nApós verificações minhas com Setor do Suporte foi necessário abrir um Protocolo para Setor de Desenvolvimento analisar o caso, segue em aberto e assim que possível traremos um retorno.', '2025-10-17 09:42:11', NULL),
(7136, 'Finalizado', '2025-10-17 09:55:36', 2750, 446, 'Feita verificação no computador o mesmo apresentou no botão de power. Foi feita a troca das conectividades na placa mãe fazendo com que somente fosse possível ligar o computador com o botão de reset feito isso o computador já se encontra funcionando normalmente.', '2025-10-17 09:55:36', NULL),
(7137, 'Aguardando Outros', '2025-10-17 10:08:26', 2803, 443, '142190 ticket no desenvolvimento', '2025-10-17 10:08:26', NULL),
