(7150, 'Aguardando Comercial', '2025-10-17 14:49:37', 2903, 443, 'Na verificação foi observado que ambos os relógios não estavam conectados sendo necessário agendar visita para uma melhor avaliação do problema.', '2025-10-17 14:49:37', NULL),
