(7758, 'Finalizado', '2025-10-30 10:44:34', 3082, 443, 'Orientei como proceder nesses casos pois mesmo tendo atestado do dia o colaborador foi na empresa e bateu o ponto.', '2025-10-30 10:44:34', NULL),
