(7793, 'Finalizado', '2025-10-30 15:15:42', 3027, 443, 'Fechamento realizado junto com a solicitante via acesso remoto apontando as principais ocorrências e realizado os ajustes de esquecimento de registro e trocas de escalas durante o mês.', '2025-10-30 15:15:42', NULL),
