(7867, 'Finalizado', '2025-10-31 14:43:02', 3116, 446, 'Foi feito o teste de velocidade do wi-fi no computador o mesmo não está atendendo a demanda atual sendo necessário a troca do adaptador wi-fi que mal fica conectado já rede da clínica.', '2025-10-31 14:43:02', NULL),
(7868, 'Finalizado', '2025-10-31 14:44:58', 3115, 446, 'Foi feita uma verificação no computador o mesmo de encontra com a placa última que não atende mas a demanda atual sendo necessário a troca da mesmo, o adaptador wi-fi também precisar ser trocado pois o mesmo não é de boa qualidade e não supre internet suficiente para o computador acessar o navegador.', '2025-10-31 14:44:58', NULL),
(7869, 'Finalizado', '2025-10-31 14:48:20', 3117, 446, 'Foi visto que o adaptador wi-fi que se encontra neste computador não atende a demanda atual que a internet exige sendo necessário a troca do mesmo.', '2025-10-31 14:48:20', NULL),
