(8529, 'Finalizado', '2025-11-13 11:34:38', 3133, 447, 'Foi confirmado a visita dos técnicos na clinica, informaram que \"por lá estava tudo OK, precisaria conferir com o TI\", fiz o acesso e testei a internet está bem melhor do que no momento em que o chamado foi aberto. Internet se encontra funcionando normalmente. Diferença de 15mb para 93 mb.', '2025-11-13 11:34:38', NULL),
(8530, 'Em Atendimento', '2025-11-13 11:40:02', 3219, 444, 'Inicializado as 11:40:02 hs. do dia 13-11-2025', '2025-11-13 11:40:02', NULL),
