(9102, 'Finalizado', '2025-11-27 10:30:21', 3330, 446, 'Foi feita a limpeza da placa pois a mesma estava bem empoeirada e feita a troca da pasta térmica. Feito isto o computador já se encontra funcionando normalmente.', '2025-11-27 10:30:21', NULL),
