(9122, 'Pausado', '2025-11-27 15:10:35', 2230, 447, 'Feito tentativas de contato com provedor mais sem atualização referente a portabilidade. Será feito mais tentativas para uma atualização.', '2025-11-27 15:10:35', NULL),
