(9136, 'Finalizado', '2025-11-27 16:25:01', 3400, 444, 'Fechamento dos cartões  de ponto do período de 27/10 a 26/11. Lançamento de justificativas, impressão e envio dos cartões no email ', '2025-11-27 16:25:01', NULL),
(9137, 'Finalizado', '2025-11-27 16:29:26', 3426, 446, 'Foi feita a instalação do driver do ecuro e feito o teste no leitor, foi orientado que entrassem em contato com o suporte para que façam a configuração do leitor.', '2025-11-27 16:29:26', NULL),
