(9139, 'Aguardando Cliente', '2025-11-27 16:37:57', 3419, 445, 'Entrei em contato com o cliente e mandei o link da reunião, não obtive retorno do mesmo para da segmento na apresentação, deixei recado no whatsapp.', '2025-11-27 16:37:57', NULL),
(9140, 'Aguardando Cliente', '2025-11-27 16:38:51', 3386, 445, 'Cliente me mandou mensagem informando que o Dr Claiton só vai está na clinica na Segunda (01/12)', '2025-11-27 16:38:51', NULL),
(9141, 'Reagendado', '2025-11-27 16:41:56', 3419, 445, 'Reagendado as 16:41:56 hs. do dia 27-11-2025', '2025-11-27 16:41:56', NULL),
