(9491, 'Em Atendimento', '2025-12-03 11:05:54', 3459, 446, 'Inicializado as 11:05:54 hs. do dia 03-12-2025', '2025-12-03 11:05:54', NULL),
(9492, 'Em Atendimento', '2025-12-03 11:12:07', 3538, 446, 'Inicializado as 11:12:07 hs. do dia 03-12-2025', '2025-12-03 11:12:07', NULL),
(9493, 'Em Atendimento', '2025-12-03 11:12:13', 3539, 446, 'Inicializado as 11:12:13 hs. do dia 03-12-2025', '2025-12-03 11:12:13', NULL),
