(9528, 'Aguardando Comercial', '2025-12-03 16:07:09', 3479, 445, 'Ao realizar a avaliação técnica do equipamento, foi identificado que o mesmo apresenta defeito no módulo biométrico, impedindo o devido funcionamento da leitura da digital, sendo necessário a troca para que equipamento volte a normalidade. Foi feito o Laudo e encaminhado para o setor comercial para enviar junto ao orçamento de reparo.', '2025-12-03 16:07:09', NULL),
(9529, 'Em Atendimento', '2025-12-03 16:07:56', 3549, 445, 'Inicializado as 16:07:56 hs. do dia 03-12-2025', '2025-12-03 16:07:56', NULL),
