(9622, 'Aguardando Cliente', '2025-12-04 13:38:06', 3547, 446, 'A auxiliar informou que não esta na clinica no momento e que assim que retornar ira nos comunicar para darmos continuidade.', '2025-12-04 13:38:06', NULL),
(9623, 'Aguardando Comercial', '2025-12-04 13:39:18', 3528, 446, 'A responsável informou que já não se encontra mas na clinica e que só ira retornar amanhã para darmos continuidade a este chamado.', '2025-12-04 13:39:18', NULL),
