(9636, 'Finalizado', '2025-12-04 15:19:31', 3566, 445, 'Usuários criados conforme solicitado, liberado autorização LGPD, de acordo com a solicitante as mesmas vão ter controle para cadastrar e manusear o ponto livremente sem restrições.', '2025-12-04 15:19:31', NULL),
(9637, 'Aguardando Cliente', '2025-12-04 15:32:34', 3532, 445, 'Entrei em contato com o cliente novamente, e o mesmo informou que está providenciando a instalação do relógio no local, para podermos da segmento ao atendimento.', '2025-12-04 15:32:34', NULL),
(9638, 'Em Atendimento', '2025-12-04 16:02:20', 3567, 445, 'Inicializado as 16:02:20 hs. do dia 04-12-2025', '2025-12-04 16:02:20', NULL),
(9639, 'Aguardando Cliente', '2025-12-04 16:14:19', 3567, 445, 'Liguei mas não tive resposta, deixei recado no whatsapp de Nathali, aguardando retorno para da segmento.', '2025-12-04 16:14:19', NULL),
(9640, 'Finalizado', '2025-12-04 16:21:17', 3564, 446, 'Foi feito o acesso nos computadores e foi refeita a conexão da impressora nestes por meio de IP do computador originário.', '2025-12-04 16:21:17', NULL),
(9641, 'Reagendado', '2025-12-04 16:38:19', 3567, 445, 'Reagendado as 16:38:19 hs. do dia 04-12-2025', '2025-12-04 16:38:19', NULL),
