(9844, 'Pausado', '2025-12-10 11:15:07', 3598, 447, '7 andar todos os notebooks já possuem anydesk, no 6 a Dra. Thais também possui, faltando os dois Drs. que não se encontravam no momento para por a senha do notebook. ', '2025-12-10 11:15:07', NULL),
(9845, 'Em Atendimento', '2025-12-10 11:15:10', 3598, 447, 'Inicializado as 11:15:10 hs. do dia 10-12-2025', '2025-12-10 11:15:10', NULL),
(9846, 'Reagendado', '2025-12-10 11:15:34', 3598, 447, 'Reagendado as 11:15:34 hs. do dia 10-12-2025', '2025-12-10 11:15:34', NULL),
(9847, 'Finalizado', '2025-12-10 11:26:32', 3579, 445, 'Treinamento realizado com sucesso, treinei a cliente a como utilizar a escala mensal corretamente, como lançar as folgas normais e compensatórias, e se atentar a troca de folgas que houverem durante o mês, informei que deve se atentar a quantidade de horas que o colaborador possui no banco de horas, para da folgas compensatorias quando necessario, para manter o banco sempre de acordo antes do mesmo finalizar. Orientei a como acompanhar os pontos dos funcionários, e de como verificar a quantidade de saldo de horas que cada um possui. Ensinei a como validar as solicitações do central do funcionário, como aceitar ou descartar caso a justificativa esteja em inconformidade, e por último ensinei a como usar o app central do funcionário para acompanhamento pelo celular.', '2025-12-10 11:26:32', NULL),
(9848, 'Em Atendimento', '2025-12-10 11:29:13', 3619, 445, 'Inicializado as 11:29:13 hs. do dia 10-12-2025', '2025-12-10 11:29:13', NULL),
(9849, 'Finalizado', '2025-12-10 11:34:02', 3619, 445, 'Orientei o cliente a como ver os colaboradores desligados, e retornar o cadastro para ativos para validar e gerar o espelho deste funcionário. ', '2025-12-10 11:34:02', NULL),
(9850, 'Em Atendimento', '2025-12-10 11:34:10', 3621, 445, 'Inicializado as 11:34:10 hs. do dia 10-12-2025', '2025-12-10 11:34:10', NULL),
(9851, 'Em Atendimento', '2025-12-10 11:55:22', 3622, 445, 'Inicializado as 11:55:22 hs. do dia 10-12-2025', '2025-12-10 11:55:22', NULL),
(9852, 'Finalizado', '2025-12-10 11:57:55', 3620, 447, 'Whatsapp está conectado no emulador do computador porém ele está restringido por validação do Whatsapp por 24h, só depois do período de restrição será liberado novamente. ', '2025-12-10 11:57:55', NULL),
(9853, 'Pausado', '2025-12-10 12:10:02', 3622, 445, 'Pausa para o almoço, será retomado o atendimento assim que retornar.', '2025-12-10 12:10:02', NULL),
(9854, 'Aguardando Cliente', '2025-12-10 12:12:16', 3621, 445, 'Ao realizar a verificação, foi identificado que o registro de ambas colaboradoras está intermitente, funcionário hora sim e hora não, ao olhar a facial cadastrada, ambas foram tiradas usando óculos, e com qualidade muito abaixo do recomendado, podendo ser um dos fatores que estava influenciando na intermitência, orientei a cliente a recadastrar a foto de ambas, e fazer o teste novamente, em contrapartida, ajustei também o nível de reconhecimento da facial para que diminua a chance de erros. Aguardando retorno da cliente para validar se após os testes foi normalizado.', '2025-12-10 12:12:16', NULL);
INSERT INTO `adms_cham_hist` (`id`, `status`, `dt_status`, `cham_id`, `usr_id`, `obs`, `created`, `modified`) VALUES
