(10607, 'Aguardando Cliente', '2025-12-29 11:14:02', 3820, 459, 'Orçamento de visita tecnica para treinamento enviada, aguardando retorno do cliente para agendarmos o dia e horário.  ', '2025-12-29 11:14:02', NULL),
