(10661, 'Finalizado', '2025-12-30 10:29:23', 3822, 445, 'Fechamento parcial realizado até o dia 30/12. Feito lançamento dos ajustes, atestados e faltas.', '2025-12-30 10:29:23', NULL),
(10662, 'Aguardando Cliente', '2025-12-30 10:34:36', 3796, 445, 'Migração e implantação concluida, criei usuário de acesso para Luzinete (Aguardando Suzana me encaminhar os dados para que eu possa criar outro usuário exclusivo para ela), cliente vai utilizar app central do funcionário para os colaboradores registrarem ponto na empresa ou home office, com reconhecimento facial (Ainda não foi cadastrado) Repassei um básico resumo de como fazer os lançamentos no ponto para Luzinete, informei que o relógio que a cliente possui não tem integração com secullum web, se trata de um ZPM, informei que poderíamos fazer a tentativa de emitir o arquivo fiscal com pen drive e importar no sistema para recuperar as batidas do dia 22/12/2025 até 30/12/2025, sigo no aguardo da mesma com um pen drive para tentarmos fazer esse processo. Ficou pendente o treinamento da cliente, devido a mesma não ter disponibilidade hoje e só retorna dia 5, ficaram de informar um dia que estarão disponíveis para ter o treinamento completo do sistema. Backup do sistema foi salvo em Nuvem e foi feito o cancelamento da licença. Sigo no aguardo dos retornos da clientes (Dados para criar usuário, estar com pen drive para tentar gerar o AFD do relógio e informar o dia que deseja o treinamento.). ', '2025-12-30 10:34:36', NULL),
(10663, 'Em Atendimento', '2025-12-30 10:53:27', 3837, 445, 'Inicializado as 10:53:27 hs. do dia 30-12-2025', '2025-12-30 10:53:27', NULL);
INSERT INTO `adms_cham_hist` (`id`, `status`, `dt_status`, `cham_id`, `usr_id`, `obs`, `created`, `modified`) VALUES
(10664, 'Finalizado', '2025-12-30 10:55:56', 3722, 446, 'O filtro de linha que estava sendo utilizado sofreu uma queda e após isto o computador não estava ligando mais, foi posto o computador diretamente na tomada e o mesmo voltou a funcionar normalmente.', '2025-12-30 10:55:56', NULL),
(10665, 'Finalizado', '2025-12-30 10:56:43', 3721, 446, 'O doutor informou que não havia nenhum problema com o computador.', '2025-12-30 10:56:43', NULL),
(10666, 'Finalizado', '2025-12-30 11:00:28', 3837, 445, 'Cliente desejava aprender como realizar a abertura de um período encerrado, orientei a como fazer mas deixei ciente que pode haver recalculo que impacte no saldo atual, tendo em vista que o mesmo usa banco de horas.', '2025-12-30 11:00:28', NULL),
(10667, 'Aguardando Comercial', '2025-12-30 11:09:29', 3825, 444, 'Equipamento retirado para verificação em bancada técnica referente ao erro apresentado de \"ticket pendente\" e na comunicação da rede. \r\nSetor comercial assim que tiver o diagnóstico do técnico enviará orçamento. Equipamento com fonte, suporte de papel e bateria nobreak. ', '2025-12-30 11:09:29', NULL),
(10668, 'Finalizado', '2025-12-30 12:06:30', 3833, 443, 'Treinamento realizado do sistema todas as dúvidas foram tiradas e orientações sobre e controle do ponto e banco de horas a gestora Laiz foi a responsável por mediar as observações e se mostrou satisfeita com as explicações.', '2025-12-30 12:06:30', NULL),
(10669, 'Pausado', '2025-12-30 12:27:59', 3836, 447, 'Finalizando o chamado 3835 para verificar se o email Influência no sistema.', '2025-12-30 12:27:59', NULL),
