(10929, 'Finalizado', '2026-01-07 09:55:45', 3809, 446, 'Foi feita a troca da fonte e a troca do cabo sata do computador e o mesmo já voltou a funcionar normalmente.', '2026-01-07 09:55:45', NULL),
