(11249, 'Finalizado', '2026-01-13 16:39:00', 4016, 443, 'Na verificação foi visto que o equipamento estava desconectado, orientei a a testar a conexão no equipamento e a comunicação foi restabelecida.', '2026-01-13 16:39:00', NULL),
